                          else if (val < -0.3) { bg = 'bg-red-500/10 border-red-500/20'; text = 'text-red-300'; }

                          return (
                            <td key={colSym} className={`p-3 text-center rounded-lg border border-transparent ${bg} ${text} transition-colors hover:border-white/20`}>
                              {val.toFixed(2)}
