                console.error("Failed to fetch sentiment data", err);
            } finally {
                setLoading(false);
            }
        };
        fetchSentiment();
    }, []);

    if (loading) return <div className="flex h-64 items-center justify-center"><Activity className="animate-spin text-pink-500 w-8 h-8"/></div>;
