                                barSize={24} 
                                data={data.chartData} 
                                startAngle={180} endAngle={0}
                            >
                                <PolarAngleAxis type="number" domain={[0, 100]} angleAxisId={0} tick={false} />
                                <RadialBar minAngle={15} background={{ fill: 'rgba(255,255,255,0.05)' }} clockWise={false} dataKey="value" cornerRadius={12} />
